import jwt
from jwt import InvalidTokenError, ExpiredSignatureError, DecodeError

def decode_and_verify_jwt(token, secret, algorithms=['HS256'], required_claims=['exp']):
    try:
        # Decode the JWT token
        decoded = jwt.decode(token, secret, algorithms=algorithms, options={"require": required_claims})
        return decoded
    except ExpiredSignatureError:
        return "Token has expired."
    except InvalidTokenError:
        return "Invalid token."
    except DecodeError:
        return "Error decoding token."

